def configure_from_file(kong: KongAdminClient, config_file: str):
    """Configure Kong from a JSON configuration file."""
    print(f"📄 Loading configuration from: {config_file}")

    with open(config_file, "r") as f:
        config = json.load(f)

    # Process upstreams and targets
    for upstream_config in config.get("upstreams", []):
        targets = upstream_config.pop("targets", [])
        kong.create_upstream(**upstream_config)
        for target in targets:
            kong.add_target(upstream_config["name"], **target)

    # Process services
    for service_config in config.get("services", []):
        kong.create_service(**service_config)

    # Process routes
    for route_config in config.get("routes", []):
        service = route_config.pop("service")
        kong.create_route(service_name_or_id=service, **route_config)

    # Process plugins
    for plugin_config in config.get("plugins", []):
        kong.add_plugin(**plugin_config)

    # Process consumers
    for consumer_config in config.get("consumers", []):
        credentials = consumer_config.pop("credentials", {})
        consumer = kong.create_consumer(**consumer_config)
        username = consumer_config.get("username")

        for key_auth in credentials.get("key_auth", []):
            kong.create_consumer_key_auth(username, **key_auth)
        for basic_auth in credentials.get("basic_auth", []):
            kong.create_consumer_basic_auth(username, **basic_auth)
        for jwt in credentials.get("jwt", []):
            kong.create_consumer_jwt(username, **jwt)

    print("✅ Configuration from file complete!")


