def wait_for_kong(admin_url: str, max_retries: int = 30, retry_interval: int = 2):
    """Wait for Kong to be ready."""
    print(f"⏳ Waiting for Kong at {admin_url}...")
    for i in range(max_retries):
        try:
            response = requests.get(f"{admin_url}/status", timeout=5)
            if response.status_code == 200:
                print("✅ Kong is ready!")
                return True
        except requests.exceptions.ConnectionError:
            pass
        print(f"   Retry {i + 1}/{max_retries}...")
        time.sleep(retry_interval)
    print("❌ Kong did not become ready in time.")
    return False


if __name__ == "__main__":
    import argparse

    parser = argparse.ArgumentParser(
        description="Kong API Gateway Configuration Tool",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
Examples:
  %(prog)s                              # Run sample infrastructure setup
  %(prog)s --admin-url http://kong:8001  # Custom Kong admin URL
  %(prog)s --config kong_config.json     # Configure from file
  %(prog)s --generate-config             # Generate sample config file
  %(prog)s --cleanup                     # Remove all configuration
  %(prog)s --export                      # Export current configuration
  %(prog)s --wait                        # Wait for Kong before configuring
        """,
    )

    parser.add_argument(
        "--admin-url",
        default="http://localhost:8001",
        help="Kong Admin API URL (default: http://localhost:8001)",
    )
    parser.add_argument(
        "--config",
        help="Path to JSON configuration file",
    )
    parser.add_argument(
        "--generate-config",
        action="store_true",
        help="Generate a sample configuration file",
    )
    parser.add_argument(
        "--cleanup",
        action="store_true",
        help="Remove all Kong configuration",
    )
    parser.add_argument(
        "--export",
        action="store_true",
        help="Export current Kong configuration as JSON",
    )
    parser.add_argument(
        "--wait",
        action="store_true",
        help="Wait for Kong to be ready before configuring",
    )
    parser.add_argument(
        "--timeout",
        type=int,
        default=30,
        help="Request timeout in seconds (default: 30)",
    )

    args = parser.parse_args()

    if args.generate_config:
        generate_sample_config_file()
        sys.exit(0)

    if args.wait:
        if not wait_for_kong(args.admin_url):
            sys.exit(1)

    kong_client = KongAdminClient(admin_url=args.admin_url, timeout=args.timeout)

    if args.cleanup:
        kong_client.cleanup_all()
    elif args.export:
        config = kong_client.export_config()
        print(json.dumps(config, indent=2, default=str))
    elif args.config:
        configure_from_file(kong_client, args.config)
    else:
        configure_sample_infrastructure(kong_client)